-- Seed first 16 philosophy/ethics/morality questions into questions table.
-- Run after schema (e.g. mysql ... align < seed_questions_philosophy.sql)
-- Types: 0=single select, 1=multi-select, 2=scale, 3=free text, 4=ranking, 5=yes/no, 6=other

USE align;

ON DUPLICATE KEY UPDATE question_data = VALUES(question_data);
